import os
import re
from src.nodes.base import BaseNode
from src.utils.prism_core import resolve_prism_core
from src.utils.prism_config import (
    resolve_cfg, get_departments, resolve_dept_folder,
    get_entity_scenefiles_root, build_abbrev_map
)

SCENE_EXTS = {
    '.blend', '.hip', '.hipnc', '.hiplc', '.ma', '.mb',
    '.nk', '.comp', '.aep', '.nuke', '.katana', '.klf',
    '.modo', '.lxo', '.c4d', '.max', '.ztl', '.zpr',
    '.usd', '.usda', '.usdc', '.usdz',
}
META_SUFFIXES = ('versioninfo.json', 'preview.jpg', 'preview.png', 'preview.jpeg')

def _is_scene_file(name):
    nl = name.lower()
    if any(nl.endswith(s) for s in META_SUFFIXES):
        return False
    return os.path.splitext(nl)[1] in SCENE_EXTS

def _version_num(name):
    m = re.search(r'_v(\d+)', name, re.IGNORECASE)
    return int(m.group(1)) if m else 0

def _parse_version(name):
    m = re.search(r'(_v\d+)', name, re.IGNORECASE)
    return m.group(1)[1:] if m else ''

class PrismGetSceneFilesNode(BaseNode):
    name = "Prism: Get Scene Files"
    category = "DCCs"

    def __init__(self):
        super().__init__(use_exec=False)
        self.icon_path = "icons/prism_icon.png"
        self.add_input("core", "any")
        self.add_input("entity", "dict")
        self.add_input("department", "string", widget_type="text", default="")
        self.add_input("task", "string", widget_type="text", default="")
        self.add_output("scenefiles", "list")
        self.add_output("latest", "string")
        self.add_output("count", "int")

    def _scan_disk(self, scenes_root, dept_abbrev, task_input):
        dept_dir = None
        for entry in os.scandir(scenes_root):
            if entry.is_dir() and entry.name.lower() == dept_abbrev:
                dept_dir = entry.path
                break
        if not dept_dir:
            self.log_error(f"dept folder '{dept_abbrev}' not found in {scenes_root}")
            return []
        task_dirs = []
        for entry in os.scandir(dept_dir):
            if not entry.is_dir():
                continue
            if task_input and entry.name.lower() != task_input.lower():
                continue
            task_dirs.append(entry)
        if not task_dirs:
            available = [e.name for e in os.scandir(dept_dir) if e.is_dir()]
            self.log_info(f"no task folder matching '{task_input}' — available: {available}")
            return []
        files = []
        for task_entry in task_dirs:
            for fentry in os.scandir(task_entry.path):
                if fentry.is_file() and _is_scene_file(fentry.name):
                    files.append({
                        'path': fentry.path,
                        'filename': fentry.name,
                        'version': _parse_version(fentry.name),
                        'task': task_entry.name,
                        'department': dept_abbrev,
                    })
        files.sort(key=lambda f: _version_num(f['filename']))
        self.log_info(f'disk scan found {len(files)} scene file(s)')
        return files

    async def execute(self, inputs):
        core = resolve_prism_core(inputs)
        entity = inputs.get('entity') or {}
        dept_input = (inputs.get('department') or '').strip()
        task_input = (inputs.get('task') or '').strip()
        if core is None:
            self.log_error('No PrismCore found.')
            return {'scenefiles': [], 'latest': '', 'count': 0}
        cfg_path = resolve_cfg(core=core, entity=entity)
        entity_type = entity.get('type', 'shot')
        dept_defs = get_departments(core, cfg_path, entity_type)
        dept_abbrev = resolve_dept_folder(dept_input, dept_defs) if dept_input else ''
        if dept_input and not dept_abbrev:
            dept_abbrev = dept_input.lower()
        abbrev_map = build_abbrev_map(dept_defs)
        files = []
        try:
            raw = list(core.entities.getScenefiles(entity) or [])
            if raw:
                if dept_abbrev:
                    def dept_match(f):
                        sf_dept = (f.get('department', f.get('step', '')) or '').lower()
                        if sf_dept == dept_abbrev:
                            return True
                        entry = abbrev_map.get(sf_dept)
                        return entry is not None and entry.get('abbreviation') == dept_abbrev
                    raw = [f for f in raw if isinstance(f, dict) and dept_match(f)]
                if task_input:
                    raw = [f for f in raw if isinstance(f, dict)
                           and (f.get('task', '') or '').lower() == task_input.lower()]
                files = raw
                self.log_info(f'getScenefiles: {len(files)} file(s)')
        except Exception as e:
            self.log_info(f'getScenefiles error: {e}')
        if not files and dept_abbrev:
            scenes_root = get_entity_scenefiles_root(entity, core, cfg_path)
            if scenes_root:
                files = self._scan_disk(scenes_root, dept_abbrev, task_input)
        latest = files[-1].get('path', '') if files and isinstance(files[-1], dict) else ''
        self.log_info(f'latest: {latest}')
        return {'scenefiles': files, 'latest': latest, 'count': len(files)}

def register_node():
    return PrismGetSceneFilesNode
